    fn add_actor_assigns_sequential_ids() {
        let mut rt = SingleThreadRuntime::new("test.ids");
        assert_eq!(rt.add_actor(Box::new(Sink)), 0);
        assert_eq!(rt.add_actor(Box::new(Sink)), 1);
        assert_eq!(rt.add_actor(Box::new(Sink)), 2);
    }
}

